Let's write the BIT class.
```typescript
class BIT {
    n: number;
    tree: number[];
    constructor(n: number) {
        this.n = n;
        this.tree = new Array(n + 1).fill(0);
    }
    add(i: number, delta: number) {
        while (i <= this.n) {
            this.tree[i] += delta;
            i += i & (-i);
        }
    }
    query(i: number) {
        let sum = 0;
        while (i > 0) {
            sum += this.tree[i];
            i -= i & (-i);
        }
        return sum;
    }
}
```

