Let's write out the full code.

```typescript
import * as fs from 'fs';

class BIT {
    n: number;
    tree: number[];
    constructor(n: number) {
        this.n = n;
        this.tree = new Array(n + 1).fill(0);
    }
    add(i: number, delta: number) {
        while (i <= this.n) {
            this.tree[i] += delta;
            i += i & (-i);
        }
    }
    query(i: number) {
        let sum = 0;
        while (i > 0) {
            sum += this.tree[i];
            i -= i & (-i);
        }
        return sum;
    }
}

function main() {
    const input = fs.readFileSync(0, "utf8").trim().split(/\s+/);
    let idx = 0;
    const next = () => parseInt(input[idx++], 10);

    const N = next();
    const Q = next();

    const intervals: [number, number][] = [];
    const coordSet = new Set<number>();

    for (let i = 0; i < N; i++) {
        const l = next();
        const r = next();
        intervals.push([l, r]);
        coordSet.add(l);
        coordSet.add(r + 1);
    }

    const queries: number[] = [];
    for (let i = 0; i < Q; i++) {
        const x = next();
        queries.push(x);
        coordSet.add(x);
    }

    const coords = Array.from(coordSet).sort((a, b) => a - b);
    const coordToIndex = new Map<number, number>();
    for (let i = 0; i < coords.length; i++) {
        coordToIndex.set(coords[i], i + 1);
    }

    const M = coords.length;
    const bit = new BIT(M);

    for (const [l, r] of intervals) {
        bit.add(coordToIndex.get(l)!, 1);
        bit.add(coordToIndex.get(r + 1)!, -1);
    }

    const results: string[] = [];
    for (const x of queries) {
        const ans = bit.query(coordToIndex.get(x)!);
        results.push(ans.toString());
    }

    console.log(results.join(' '));
}

main();
```

